@startuml
' Define styles
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor White
  BorderColor Black
  FontColor Black
}
skinparam note {
  BackgroundColor #FFFFE0
  BorderColor Black
  FontColor Black
}

' Define classes with their attributes and methods
class UC_node {
  + name: String
}

class Robustness_dia {
  + uc_node: UC_node
  + nodes: List<Rob_node>
  + edges: List<Rob_edge>
  + addNode()
  + addEdge()
}

class Rob_node {
  + name: String
  + edges: List<Rob_edge>
}

class Rob_edge {
  + name: String
  + begin: Rob_node
  + end: Rob_node
}

class Rob_actor {
}

class Rob_boundary {
  + layout: Layout
  + is_error: bool
}

class Rob_control {
}

class Rob_entity {
  + format: Format
}

' Define relationships
UC_node --|> Robustness_dia : composition
Robustness_dia --o Rob_node : aggregation
Robustness_dia --o Rob_edge : aggregation
Rob_node --o Rob_edge : aggregation
Rob_actor --> Rob_node : inheritance
Rob_boundary --> Rob_node : inheritance
Rob_control --> Rob_node : inheritance
Rob_entity --> Rob_node : inheritance

' Define notes
note "Robustness – Rob\nUse Case – UC"

@enduml
